import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom'; // Assuming react-router-dom for URL parameters

// Mock API call function - in a real application, this would be an actual API call
// to your backend, for example, using axios or fetch.
// This mock simulates the data structure returned by user.services.js's getExamReviewDetails
const fetchExamReview = async (userId, attemptId) => {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 800));

  // --- Mock Data ---
  // This structure mimics the output of a populated ExamAttempt document.
  // The 'answers' array contains populated 'questionId' objects.
  const mockExamAttempt = {
    _id: attemptId,
    userId: userId,
    category: 'Intermediate',
    section: 'Intermediate Challenge',
    set: 'Set 2',
    score: 70,
    totalQuestions: 10,
    correctAnswers: 7,
    duration: 600, // seconds
    submittedAt: new Date().toISOString(),
    answers: [
      {
        _id: 'ans1',
        questionId: {
          _id: 'q1',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'What is the capital of France?',
          questionImage: 'https://placehold.co/200x100/A8DADC/1D3557?text=Question+Image',
          options: [
            { type: 'text', content: 'Berlin' },
            { type: 'text', content: 'Madrid' },
            { type: 'text', content: 'Paris' },
            { type: 'text', content: 'Rome' },
          ],
          correctAnswer: 'c', // 'c' corresponds to Paris
        },
        selectedOption: 'c',
        isCorrect: true,
      },
      {
        _id: 'ans2',
        questionId: {
          _id: 'q2',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'Which planet is known as the Red Planet?',
          options: [
            { type: 'text', content: 'Earth' },
            { type: 'text', content: 'Mars' },
            { type: 'text', content: 'Jupiter' },
            { type: 'text', content: 'Venus' },
          ],
          correctAnswer: 'b', // 'b' corresponds to Mars
        },
        selectedOption: 'a', // Incorrectly selected Earth
        isCorrect: false,
      },
      {
        _id: 'ans3',
        questionId: {
          _id: 'q3',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'What is 7 + 8?',
          options: [
            { type: 'text', content: '14' },
            { type: 'text', content: '15' },
            { type: 'text', content: '16' },
            { type: 'text', content: '13' },
          ],
          correctAnswer: 'b', // 'b' corresponds to 15
        },
        selectedOption: 'b',
        isCorrect: true,
      },
      {
        _id: 'ans4',
        questionId: {
          _id: 'q4',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'Select the image that shows a cat.',
          options: [
            { type: 'image', content: 'https://placehold.co/100x100/E5E5E5/000000?text=Dog' },
            { type: 'image', content: 'https://placehold.co/100x100/F0F0F0/000000?text=Cat' },
            { type: 'image', content: 'https://placehold.co/100x100/E0E0E0/000000?text=Bird' },
            { type: 'image', content: 'https://placehold.co/100x100/D5D5D5/000000?text=Fish' },
          ],
          correctAnswer: 'b',
        },
        selectedOption: 'b',
        isCorrect: true,
      },
      {
        _id: 'ans5',
        questionId: {
          _id: 'q5',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'Listen and identify the animal sound.',
          questionAudio: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3', // Example audio URL
          options: [
            { type: 'text', content: 'Cow' },
            { type: 'text', content: 'Dog' },
            { type: 'text', content: 'Cat' },
            { type: 'text', content: 'Bird' },
          ],
          correctAnswer: 'a',
        },
        selectedOption: 'c', // Incorrect
        isCorrect: false,
      },
      {
        _id: 'ans6',
        questionId: {
          _id: 'q6',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'Which continent is India located in?',
          options: [
            { type: 'text', content: 'Europe' },
            { type: 'text', content: 'Africa' },
            { type: 'text', content: 'Asia' },
            { type: 'text', content: 'North America' },
          ],
          correctAnswer: 'c',
        },
        selectedOption: 'c',
        isCorrect: true,
      },
      {
        _id: 'ans7',
        questionId: {
          _id: 'q7',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'What is the largest ocean on Earth?',
          options: [
            { type: 'text', content: 'Atlantic Ocean' },
            { type: 'text', content: 'Indian Ocean' },
            { type: 'text', content: 'Arctic Ocean' },
            { type: 'text', content: 'Pacific Ocean' },
          ],
          correctAnswer: 'd',
        },
        selectedOption: 'd',
        isCorrect: true,
      },
      {
        _id: 'ans8',
        questionId: {
          _id: 'q8',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'Who painted the Mona Lisa?',
          options: [
            { type: 'text', content: 'Vincent van Gogh' },
            { type: 'text', content: 'Leonardo da Vinci' },
            { type: 'text', content: 'Pablo Picasso' },
            { type: 'text', content: 'Claude Monet' },
          ],
          correctAnswer: 'b',
        },
        selectedOption: 'a',
        isCorrect: false,
      },
      {
        _id: 'ans9',
        questionId: {
          _id: 'q9',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'What is the chemical symbol for water?',
          options: [
            { type: 'text', content: 'O2' },
            { type: 'text', content: 'CO2' },
            { type: 'text', content: 'H2O' },
            { type: 'text', content: 'NaCl' },
          ],
          correctAnswer: 'c',
        },
        selectedOption: 'c',
        isCorrect: true,
      },
      {
        _id: 'ans10',
        questionId: {
          _id: 'q10',
          category: 'Intermediate',
          section: 'Intermediate Challenge',
          set: 'Set 2',
          questionText: 'Which organ pumps blood throughout the body?',
          options: [
            { type: 'text', content: 'Lungs' },
            { type: 'text', content: 'Brain' },
            { type: 'text', content: 'Heart' },
            { type: 'text', content: 'Liver' },
          ],
          correctAnswer: 'c',
        },
        selectedOption: 'd',
        isCorrect: false,
      },
    ],
  };

  if (userId && attemptId) {
    return { data: mockExamAttempt };
  } else {
    throw new Error('User ID or Attempt ID missing for mock fetch.');
  }
};

const AnswerPage = () => {
  const { userId, attemptId } = useParams(); // Get parameters from the URL
  const [examAttempt, setExamAttempt] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const getReviewDetails = async () => {
      if (!userId || !attemptId) {
        setError(new Error('User ID or Exam Attempt ID is missing from the URL.'));
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        setError(null);
        // In a real app, replace `fetchExamReview` with your actual API call:
        // const response = await api.get(`/users/${userId}/exam-attempts/${attemptId}/review`);
        const response = await fetchExamReview(userId, attemptId);
        setExamAttempt(response.data);
      } catch (err) {
        console.error('Failed to fetch exam review:', err);
        setError(err);
      } finally {
        setLoading(false);
      }
    };

    getReviewDetails();
  }, [userId, attemptId]);

  // Helper to convert option index to character (a, b, c, d)
  const getOptionChar = (index) => String.fromCharCode(97 + index);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen p-4 bg-gray-100">
        <div className="text-xl text-gray-700">Loading exam review...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen p-4 bg-red-100 rounded-lg shadow-md">
        <div className="text-xl text-red-700">Error: {error.message}. Please try again later.</div>
      </div>
    );
  }

  if (!examAttempt) {
    return (
      <div className="flex items-center justify-center min-h-screen p-4 bg-yellow-100 rounded-lg shadow-md">
        <div className="text-xl text-yellow-700">No exam attempt found for review.</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen p-4 text-gray-800 bg-gray-100 sm:p-6 lg:p-8 font-inter">
      <div className="max-w-4xl p-6 mx-auto bg-white border border-gray-200 shadow-lg sm:p-8 rounded-xl">
        <h1 className="mb-6 text-3xl font-bold text-center text-blue-700 sm:text-4xl">Exam Review</h1>

        {/* Exam Summary */}
        <div className="grid grid-cols-1 gap-4 p-4 mb-8 text-center border border-blue-200 rounded-lg shadow-sm sm:p-6 bg-blue-50 sm:grid-cols-2 lg:grid-cols-4">
          <div className="p-3 bg-blue-100 rounded-md">
            <p className="text-sm text-blue-600">Category</p>
            <p className="text-lg font-semibold">{examAttempt.category}</p>
          </div>
          <div className="p-3 bg-blue-100 rounded-md">
            <p className="text-sm text-blue-600">Section</p>
            <p className="text-lg font-semibold">{examAttempt.section}</p>
          </div>
          <div className="p-3 bg-blue-100 rounded-md">
            <p className="text-sm text-blue-600">Set</p>
            <p className="text-lg font-semibold">{examAttempt.set}</p>
          </div>
          <div className="p-3 bg-blue-100 rounded-md">
            <p className="text-sm text-blue-600">Score</p>
            <p className="text-lg font-semibold">{examAttempt.score}%</p>
          </div>
          <div className="p-3 bg-blue-100 rounded-md">
            <p className="text-sm text-blue-600">Correct Answers</p>
            <p className="text-lg font-semibold">{examAttempt.correctAnswers} / {examAttempt.totalQuestions}</p>
          </div>
          <div className="p-3 bg-blue-100 rounded-md">
            <p className="text-sm text-blue-600">Duration</p>
            <p className="text-lg font-semibold">{Math.floor(examAttempt.duration / 60)}m {examAttempt.duration % 60}s</p>
          </div>
          <div className="p-3 bg-blue-100 rounded-md">
            <p className="text-sm text-blue-600">Submitted At</p>
            <p className="font-semibold text-gray-600 text-md">{new Date(examAttempt.submittedAt).toLocaleDateString()}</p>
          </div>
        </div>

        {/* Individual Question Review */}
        <h2 className="mb-6 text-2xl font-bold text-center text-blue-600 sm:text-3xl">Your Answers</h2>
        {examAttempt.answers.map((attempt, index) => (
          <div key={attempt._id} className="p-5 mb-8 border border-gray-200 shadow bg-gray-50 rounded-xl">
            {/* Question Header */}
            <div className="flex items-center justify-between pb-2 mb-4 border-b border-gray-200">
              <h3 className="text-xl font-semibold text-gray-700">Question {index + 1}</h3>
              {attempt.isCorrect ? (
                <span className="inline-flex items-center px-3 py-1 text-sm font-medium text-green-800 bg-green-100 rounded-full">
                  <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                  Correct
                </span>
              ) : (
                <span className="inline-flex items-center px-3 py-1 text-sm font-medium text-red-800 bg-red-100 rounded-full">
                  <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                  Incorrect
                </span>
              )}
            </div>

            {/* Question Content */}
            <p className="mb-4 text-lg text-gray-900">{attempt.questionId.questionText}</p>
            {attempt.questionId.questionImage && (
              <img
                src={attempt.questionId.questionImage}
                alt="Question illustration"
                className="h-auto max-w-full mb-4 rounded-lg shadow-sm"
                onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/200x100/CCCCCC/666666?text=Image+Not+Found"; }}
              />
            )}
            {attempt.questionId.questionAudio && (
              <audio controls className="w-full mb-4 rounded-md">
                <source src={attempt.questionId.questionAudio} type="audio/mpeg" onError={(e) => console.error("Audio error:", e)} />
                Your browser does not support the audio element.
              </audio>
            )}

            {/* Options */}
            <div className="grid grid-cols-1 gap-3 md:grid-cols-2">
              {attempt.questionId.options.map((option, optIndex) => {
                const optionChar = getOptionChar(optIndex);
                const isSelected = optionChar === attempt.selectedOption;
                const isCorrectOption = optionChar === attempt.questionId.correctAnswer;

                let optionClasses = "p-3 rounded-lg border flex items-center gap-3 transition-all duration-200";

                if (isSelected && isCorrectOption) {
                  optionClasses += " bg-green-200 border-green-500 shadow-md";
                } else if (isSelected && !isCorrectOption) {
                  optionClasses += " bg-red-200 border-red-500 shadow-md";
                } else if (isCorrectOption) {
                  // Only highlight the correct answer if the user didn't select it, or if it was the selected correct answer
                  optionClasses += " bg-green-50 border-green-300";
                } else {
                  optionClasses += " bg-white border-gray-300 hover:bg-gray-50";
                }

                return (
                  <div key={optIndex} className={optionClasses}>
                    <span className={`font-bold w-6 h-6 flex items-center justify-center rounded-full ${isSelected ? 'bg-blue-600 text-white' : 'bg-gray-200 text-gray-700'}`}>
                      {optionChar.toUpperCase()}
                    </span>
                    {option.type === 'text' && <span className="flex-1 text-base text-gray-800">{option.content}</span>}
                    {option.type === 'image' && (
                      <img
                        src={option.content}
                        alt={`Option ${optionChar}`}
                        className="max-w-[100px] h-auto rounded-md flex-1"
                        onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/100x100/CCCCCC/666666?text=Image+Not+Found"; }}
                      />
                    )}
                    {option.type === 'audio' && (
                      <audio controls className="flex-1 w-full">
                        <source src={option.content} type="audio/mpeg" onError={(e) => console.error("Audio option error:", e)} />
                        Your browser does not support the audio element.
                      </audio>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AnswerPage;
